#
# Generate vendor-specific RDMA headers from
# downloaded rdma-core headers.  These files are
# auto-generated and should not be committed.

set -euo pipefail

RDMA_EP_DIR="$1"

if [ -z "$RDMA_EP_DIR" ]; then
  echo "Usage: $0 <rdma_ep_dir>"
  exit 1
fi

echo "Generating vendor-specific RDMA headers..."

# Generate MLX5 vendor header
echo "  - Generating mlx/mlx5-rdma.h..."
mkdir -p "$RDMA_EP_DIR/mlx"
cat > "$RDMA_EP_DIR/mlx/mlx5-rdma.h" << 'EOF'
/* Copyright (c) Advanced Micro Devices, Inc. All rights reserved.
 *
 * SPDX-License-Identifier: MIT
 *
 * AUTO-GENERATED FILE - DO NOT EDIT
 * Generated by scripts/build/generate-rdma-vendor-headers.sh
 * Source: rdma-core repository providers/mlx5/
 */

#ifndef MLX5_RDMA_H
#define MLX5_RDMA_H

#include "../rdma-ep.h"

/*
 * MLX5 (Mellanox/NVIDIA ConnectX) RDMA Provider
 *
 * Reference: providers/mlx5/ from linux-rdma/rdma-core
 * Downloaded headers in include/external/rdma/mlx/ for reference
 */

// MLX5-specific WQE opcodes
#define MLX5_OPCODE_SEND 0x0A
#define MLX5_OPCODE_SEND_IMM 0x0B
#define MLX5_OPCODE_RDMA_WRITE 0x08
#define MLX5_OPCODE_RDMA_WRITE_IMM 0x09
#define MLX5_OPCODE_RDMA_READ 0x10

// MLX5-specific flags
#define MLX5_WQE_CTRL_SOLICITED (1 << 1)
#define MLX5_WQE_CTRL_FENCE (1 << 6)
#define MLX5_SEND_WQE_BB 64 // Basic block size

// MLX5-specific CQE fields
#define MLX5_CQE_SYNDROME_LOCAL_LENGTH_ERR 0x01
#define MLX5_CQE_SYNDROME_LOCAL_QP_OP_ERR 0x02
#define MLX5_CQE_SYNDROME_REMOTE_ACCESS_ERR 0x10

// Helper function to set MLX5-specific WQE fields
__host__ __device__ static inline void
mlx5_wqe_set_vendor_specific(struct rdma_wqe* wqe, uint32_t qp_num,
                              bool solicited, bool fence) {
  uint64_t flags = 0;
  if (solicited)
    flags |= MLX5_WQE_CTRL_SOLICITED;
  if (fence)
    flags |= MLX5_WQE_CTRL_FENCE;
  wqe->vendor_specific = (static_cast<uint64_t>(qp_num) << 32) | flags;
}

// Helper function to extract MLX5-specific CQE fields
__host__ __device__ static inline uint32_t
mlx5_cqe_get_src_qp(const struct rdma_cqe* cqe) {
  return cqe->mlx5.src_qp;
}

__host__ __device__ static inline uint32_t
mlx5_cqe_get_flags(const struct rdma_cqe* cqe) {
  return cqe->mlx5.flags;
}

#endif // MLX5_RDMA_H
EOF

# Generate BNXT vendor header
echo "  - Generating bnxt/bnxt-rdma.h..."
mkdir -p "$RDMA_EP_DIR/bnxt"
cat > "$RDMA_EP_DIR/bnxt/bnxt-rdma.h" << 'EOF'
